'{
  "$schema": "https://vega.github.io/schema/vega/v5.json",

  "width": 800,
  "height": 260,
  "padding": 10,

  "data": [
    {
      "name": "dataset"
    },
    {
      "name": "stages",
      "source": "dataset",
      "transform": [
        {
          "type": "fold",
          "fields": [
            "Base de Datos",
            "Contactados",
            "Interactuaron con Luz",
            "Solicitaron Conexión"
          ],
          "as": ["Etapa", "Valor"]
        },
        {
          "type": "formula",
          "expr": "datum.Etapa == ''Base de Datos'' ? 0 : datum.Etapa == ''Contactados'' ? 1 : datum.Etapa == ''Interactuaron con Luz'' ? 2 : 3",
          "as": "Orden"
        },
        {
          "type": "formula",
          "expr": "datum.Etapa == ''Base de Datos'' ? ''#071126'' : datum.Etapa == ''Contactados'' ? ''#1B2942'' : datum.Etapa == ''Interactuaron con Luz'' ? ''#1FA844'' : ''#1B9D96''",
          "as": "Color"
        },
        {
          "type": "formula",
          "expr": "datum.Etapa == ''Base de Datos'' ? 520 : datum.Etapa == ''Contactados'' ? 440 : datum.Etapa == ''Interactuaron con Luz'' ? 360 : 300",
          "as": "Ancho"
        }
      ]
    }
  ],

  "scales": [
    {
      "name": "y",
      "type": "band",
      "domain": [0, 1, 2, 3],
      "range": [0, 230],
      "padding": 0.18
    }
  ],

  "marks": [
    {
      "type": "text",
      "from": { "data": "stages" },
      "encode": {
        "update": {
          "x": { "value": 120 },
          "y": {
            "signal": "scale(''y'', datum.Orden) + bandwidth(''y'')/2"
          },
          "text": { "field": "Etapa" },
          "align": { "value": "right" },
          "baseline": { "value": "middle" },
          "fontSize": { "value": 18 },
          "fill": { "value": "#111111" }
        }
      }
    },

    {
      "type": "rect",
      "from": { "data": "stages" },
      "encode": {
        "update": {
          "x": {
            "signal": "180 + (520 - datum.Ancho)/2 + 4"
          },
          "y": {
            "signal": "scale(''y'', datum.Orden) + 4"
          },
          "width": {
            "field": "Ancho"
          },
          "height": {
            "signal": "bandwidth(''y'')"
          },
          "cornerRadius": {
            "value": 4
          },
          "fill": {
            "value": "#00000022"
          }
        }
      }
    },

    {
      "type": "rect",
      "from": { "data": "stages" },
      "encode": {
        "update": {
          "x": {
            "signal": "180 + (520 - datum.Ancho)/2"
          },
          "y": {
            "signal": "scale(''y'', datum.Orden)"
          },
          "width": {
            "field": "Ancho"
          },
          "height": {
            "signal": "bandwidth(''y'')"
          },
          "cornerRadius": {
            "value": 4
          },
          "fill": {
            "field": "Color"
          }
        }
      }
    },

    {
      "type": "text",
      "from": { "data": "stages" },
      "encode": {
        "update": {
          "x": {
            "value": 440
          },
          "y": {
            "signal": "scale(''y'', datum.Orden) + bandwidth(''y'')/2"
          },
          "text": {
            "signal": "format(datum.Valor, '','')"
          },
          "align": {
            "value": "center"
          },
          "baseline": {
            "value": "middle"
          },
          "fontSize": {
            "value": 20
          },
          "fontWeight": {
            "value": "bold"
          },
          "fill": {
            "value": "white"
          }
        }
      }
    }
  ]
}'

'{
  "autosize": {
    "contains": "padding",
    "type": "fit"
  },
  "view": {
    "stroke": "transparent"
  },
  "font": "Segoe UI, wf_segoe-ui_normal, helvetica, arial, sans-serif",
  "arc": {},
  "area": {
    "line": true,
    "opacity": 0.6
  },
  "bar": {},
  "line": {
    "strokeWidth": 3,
    "strokeCap": "round",
    "strokeJoin": "round"
  },
  "point": {
    "filled": true,
    "size": 75
  },
  "rect": {},
  "text": {
    "font": "Segoe UI, wf_segoe-ui_normal, helvetica, arial, sans-serif",
    "fontSize": 12,
    "fill": "#605E5C"
  },
  "axis": {
    "ticks": false,
    "grid": false,
    "domain": false,
    "labelColor": "#605E5C",
    "labelFontSize": 12,
    "titleFont": "din, wf_standard-font, helvetica, arial, sans-serif",
    "titleColor": "#252423",
    "titleFontSize": 16,
    "titleFontWeight": "normal"
  },
  "axisQuantitative": {
    "tickCount": 3,
    "grid": true,
    "gridColor": "#C8C6C4",
    "gridDash": [
      1,
      5
    ],
    "labelFlush": false
  },
  "axisX": {
    "labelPadding": 5
  },
  "axisY": {
    "labelPadding": 10
  },
  "header": {
    "titleFont": "din, wf_standard-font, helvetica, arial, sans-serif",
    "titleFontSize": 16,
    "titleColor": "#252423",
    "labelFont": "Segoe UI, wf_segoe-ui_normal, helvetica, arial, sans-serif",
    "labelFontSize": 13.333333333333332,
    "labelColor": "#605E5C"
  },
  "legend": {
    "titleFont": "Segoe UI, wf_segoe-ui_normal, helvetica, arial, sans-serif",
    "titleFontWeight": "bold",
    "titleColor": "#605E5C",
    "labelFont": "Segoe UI, wf_segoe-ui_normal, helvetica, arial, sans-serif",
    "labelFontSize": 13.333333333333332,
    "labelColor": "#605E5C",
    "symbolType": "circle",
    "symbolSize": 75
  },
  "path": {},
  "shape": {},
  "symbol": {
    "strokeWidth": 1.5,
    "size": 50
  }
}'
